    private void GetResultsData()
    {
        SOMatchData matchDataDoc = DatabaseManager.GetDB<SOMatchData>();
        winningTeam = matchDataDoc.winningTeam;
        defenderKill = matchDataDoc.defenderKill;
        attackerKill = matchDataDoc.attackerKill;
